#include <stdio.h>
#include <string.h>

// 1. Define the blueprint OUTSIDE of main
struct Player {
    char name[50];
    int health;
    float speed;
};

int main() {
    // 2. Create an actual player using the blueprint
    struct Player p1;

    // 3. Access the 'members' using the Dot (.) Operator
    p1.health = 100;
    p1.speed = 5.5;
    strcpy(p1.name, "Hero"); // Remember, string copy!

    printf("%s has %d HP", p1.name, p1.health);
    return 0;
}
